import React from "react";
import { positions } from "../data/data";

const Positions = () => {
  return (
    <>
      <h3 className="title">Positions ({})</h3>

      <div className="order-table">
        <table>
          <tr>
            <th>Product</th>
            <th>Instrument</th>
            <th>Qty.</th>
            <th>Avg.</th>
            <th>LTP</th>
            <th>P&L</th>
            <th>Chg.</th>
          </tr>
          {positions.map((position, index) => (
            <tr key={index}>
              <td>{position.product}</td>
              <td>{position.instrument}</td>
              <td>{position.qty}</td>
              <td>{position.avg.toFixed(2)}</td>
              <td>{position.ltp.toFixed(2)}</td>
              <td>{position.pl.toFixed(2)}</td>
              <td>{position.chg.toFixed(2)}</td>
            </tr>
          ))}
        </table>
      </div>
    </>
  );
};

export default Positions;
